namespace NotificationsApp.Services;

public class Notification
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly object _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        Add("Welcome to the notifications demo!");
        Add("Your profile was updated successfully.");
        Add("New feature: dark mode is now available.");
    }

    /// <summary>Returns all notifications.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    /// <summary>Returns notifications added after the given ID.</summary>
    public List<Notification> GetSince(int lastSeenId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    private void Add(string message)
    {
        _notifications.Add(new Notification
        {
            Id = _nextId++,
            Message = message,
            Timestamp = DateTime.UtcNow
        });
    }

    /// <summary>Simulates an external system adding notifications over time.</summary>
    public void SimulateIncoming()
    {
        lock (_lock)
        {
            var messages = new[]
            {
                "Deployment completed for service-api.",
                "CPU usage alert on node-3.",
                "User 'jdoe' logged in from a new device.",
                "Scheduled maintenance window starts in 1 hour.",
                "Build #1042 passed all tests.",
                "Disk usage warning on db-primary.",
                "New comment on pull request #87.",
            };

            var msg = messages[(_nextId - 1) % messages.Length];
            Add(msg);
        }
    }
}

