@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@implements IDisposable
@inject NotificationsApp.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@_notifications.Count</span></h1>

<ul class="list-group">
    @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
    {
        <li class="list-group-item">
            <strong>@n.Timestamp.ToString("HH:mm:ss")</strong> &mdash; @n.Message
        </li>
    }
</ul>

@code {
    private List<NotificationsApp.Services.Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    protected override void OnInitialized()
    {
        // Load initial data during prerender AND interactive init.
        // Because prerender: true, OnInitialized runs during SSR to populate
        // the fast HTML. It also runs once more when the circuit starts,
        // but we load the same data — no extra fetch penalty.
        _notifications = NotificationService.GetAll();
        _lastSeenId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires in interactive mode (not during static SSR),
            // so this is the safe place to start the polling loop.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(5000, ct).ConfigureAwait(false);

            // Simulate an external system occasionally adding a notification
            NotificationService.SimulateIncoming();

            var newItems = NotificationService.GetSince(_lastSeenId);
            if (newItems.Count > 0)
            {
                _notifications.AddRange(newItems);
                _lastSeenId = newItems.Max(n => n.Id);

                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

